$base='http://localhost:5000'; $count=300; $levels=@('debug','info','warn','error'); 1..$count | % { $i=$_; $body=@{ Stream='test-stream'; Level=$levels[(Get-Random -Maximum $levels.Count)]; Message="test-stream single message #$i - $([guid]::NewGuid())"; Attributes=@{ host=$env:COMPUTERNAME; index=$i } }; Invoke-RestMethod -Uri "$base/v1/logs" -Method Post -ContentType 'application/json' -Body (ConvertTo-Json $body -Depth 10) }